function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function pixelOffset(image, x, y) {
  return (y * image.width + x) * 4;
}

function lumaAt(image, x, y) {
  const index = pixelOffset(image, x, y);
  const data = image.data;
  return (data[index] * 0.299) + (data[index + 1] * 0.587) + (data[index + 2] * 0.114);
}

function isGridPixel(image, x, y) {
  const index = pixelOffset(image, x, y);
  const data = image.data;
  const r = data[index];
  const g = data[index + 1];
  const b = data[index + 2];
  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  return max - min <= GRID_MAX_CHANNEL_GAP && r >= GRID_MIN_LUMA && r <= GRID_MAX_LUMA;
}

function isBlueNumberPixel(image, x, y) {
  const index = pixelOffset(image, x, y);
  const data = image.data;
  const r = data[index];
  const g = data[index + 1];
  const b = data[index + 2];
  return b >= r + 16 && g >= r + 8 && lumaAt(image, x, y) < 205;
}

function longestRun(values) {
  let bestStart = -1;
  let bestEnd = -1;
  let start = -1;
  for (let index = 0; index <= values.length; index += 1) {
    if (index < values.length && values[index]) {
      if (start < 0) start = index;
      continue;
    }
    if (start >= 0 && index - start > bestEnd - bestStart) {
      bestStart = start;
      bestEnd = index;
    }
    start = -1;
  }
  return { start: bestStart, end: bestEnd, length: Math.max(0, bestEnd - bestStart) };
}

function mergeLineCandidates(candidates) {
  const groups = [];
  for (const candidate of candidates) {
    const previous = groups.at(-1);
    if (previous && candidate.position <= previous.end + 2) {
      previous.end = candidate.position;
      previous.samples.push(candidate);
      if (candidate.score > previous.best.score) previous.best = candidate;
    } else {
      groups.push({
        start: candidate.position,
        end: candidate.position,
        samples: [candidate],
        best: candidate,
      });
    }
  }
  return groups.map((group) => ({
    start: group.start,
    end: group.end,
    center: group.best.position,
    score: group.best.score,
    runStart: group.best.runStart,
    runEnd: group.best.runEnd,
  }));
}

function detectHorizontalLines(image) {
  const minimumRun = Math.max(80, Math.round(image.width * 0.42));
  const candidates = [];
  for (let y = 0; y < image.height; y += 1) {
    const flags = new Array(image.width);
    for (let x = 0; x < image.width; x += 1) flags[x] = isGridPixel(image, x, y);
    const run = longestRun(flags);
    if (run.length >= minimumRun) {
      candidates.push({ position: y, score: run.length, runStart: run.start, runEnd: run.end });
    }
  }
  return mergeLineCandidates(candidates);
}

function median(values) {
  if (!values.length) return 0;
  const sorted = [...values].sort((a, b) => a - b);
  const middle = Math.floor(sorted.length / 2);
  return sorted.length % 2 ? sorted[middle] : (sorted[middle - 1] + sorted[middle]) / 2;
}

function detectVerticalLines(image, horizontalLines) {
  const usefulLines = horizontalLines.filter((line) => line.score >= image.width * 0.6);
  if (usefulLines.length < 3) throw new Error("写真から表の横罫線を確認できませんでした");
  const tableLeft = Math.round(median(usefulLines.map((line) => line.runStart)));
  const tableRight = Math.round(median(usefulLines.map((line) => line.runEnd - 1)));
  const tableTop = usefulLines[0].start;
  const tableBottom = usefulLines.at(-1).end;
  const tableHeight = Math.max(1, tableBottom - tableTop + 1);
  const candidates = [];
  for (let x = Math.max(0, tableLeft - 3); x <= Math.min(image.width - 1, tableRight + 3); x += 1) {
    let score = 0;
    for (let y = tableTop; y <= tableBottom; y += 1) {
      if (isGridPixel(image, x, y)) score += 1;
    }
    if (score >= tableHeight * 0.68) {
      candidates.push({ position: x, score, runStart: tableTop, runEnd: tableBottom + 1 });
    }
  }
  const groups = mergeLineCandidates(candidates);
  if (groups.length < COLUMN_RATIOS.length) {
    throw new Error("写真からサイトセブン表の縦罫線を確認できませんでした");
  }
  const span = tableRight - tableLeft;
  const selected = [];
  for (const ratio of COLUMN_RATIOS) {
    const target = tableLeft + span * ratio;
    const available = groups.filter((group) => !selected.includes(group));
    const nearest = available.sort((a, b) => Math.abs(a.center - target) - Math.abs(b.center - target))[0];
    if (!nearest || Math.abs(nearest.center - target) > Math.max(8, span * 0.045)) {
      throw new Error("写真の表形式がサイトセブンの7列形式と一致しません");
    }
    selected.push(nearest);
  }
  selected.sort((a, b) => a.center - b.center);
  return { lines: selected, tableLeft, tableRight, tableTop, tableBottom };
}

function buildForegroundMask(image, bounds, isForeground) {
  const x0 = clamp(Math.ceil(bounds.x0), 0, image.width - 1);
  const x1 = clamp(Math.floor(bounds.x1), x0 + 1, image.width);
  const y0 = clamp(Math.ceil(bounds.y0), 0, image.height - 1);
  const y1 = clamp(Math.floor(bounds.y1), y0 + 1, image.height);
  const width = x1 - x0;
  const height = y1 - y0;
  const mask = new Uint8Array(width * height);
  for (let y = 0; y < height; y += 1) {
    for (let x = 0; x < width; x += 1) {
      if (isForeground(x0 + x, y0 + y)) mask[y * width + x] = 1;
    }
  }

  // 台番号リンクの下線だけを除去する。数字本体より十分長い横線を対象にする。
  for (let y = Math.floor(height * 0.5); y < height; y += 1) {
    const row = [];
    for (let x = 0; x < width; x += 1) row.push(Boolean(mask[y * width + x]));
    if (longestRun(row).length >= Math.max(8, width * 0.28)) {
      for (let x = 0; x < width; x += 1) mask[y * width + x] = 0;
    }
  }
  return { mask, width, height, x0, y0 };
}

function foregroundMask(image, bounds, darkLuma = DARK_LUMA) {
  return buildForegroundMask(
    image,
    bounds,
    (x, y) => lumaAt(image, x, y) < darkLuma
  );
}

function maskBounds(mask, width, height) {
  let minX = width;
  let maxX = -1;
  let minY = height;
  let maxY = -1;
  for (let y = 0; y < height; y += 1) {
    for (let x = 0; x < width; x += 1) {
      if (!mask[y * width + x]) continue;
      minX = Math.min(minX, x);
      maxX = Math.max(maxX, x);
      minY = Math.min(minY, y);
      maxY = Math.max(maxY, y);
    }
  }
  return maxX >= minX ? { minX, maxX, minY, maxY } : null;
}

function columnGroups(cell) {
  const bounds = maskBounds(cell.mask, cell.width, cell.height);
  if (!bounds) return [];
  const groups = [];
  let start = -1;
  for (let x = bounds.minX; x <= bounds.maxX + 1; x += 1) {
    let occupied = false;
    if (x <= bounds.maxX) {
      for (let y = bounds.minY; y <= bounds.maxY; y += 1) {
        if (cell.mask[y * cell.width + x]) {
          occupied = true;
          break;
        }
      }
    }
    if (occupied && start < 0) start = x;
    if (!occupied && start >= 0) {
      groups.push({ x0: start, x1: x, y0: bounds.minY, y1: bounds.maxY + 1 });
      start = -1;
    }
  }
  return groups;
}

function normalizeGlyph(cell, rect) {
  let minX = rect.x1;
  let maxX = rect.x0 - 1;
  let minY = rect.y1;
  let maxY = rect.y0 - 1;
  for (let y = rect.y0; y < rect.y1; y += 1) {
    for (let x = rect.x0; x < rect.x1; x += 1) {
      if (!cell.mask[y * cell.width + x]) continue;
      minX = Math.min(minX, x);
      maxX = Math.max(maxX, x);
      minY = Math.min(minY, y);
      maxY = Math.max(maxY, y);
    }
  }
  if (maxX < minX || maxY < minY) return null;
  const sourceWidth = maxX - minX + 1;
  const sourceHeight = maxY - minY + 1;
  // 同じ表内では文字サイズが一定なので、拡大せず原寸の形を比較する。
  // 大きな画像だけ縮小し、ベースライン（文字の下端）を揃える。
  const scale = Math.min(1,
    (NORMALIZED_WIDTH - 2) / sourceWidth,
    (NORMALIZED_HEIGHT - 2) / sourceHeight
  );
  const renderedWidth = Math.max(1, Math.round(sourceWidth * scale));
  const renderedHeight = Math.max(1, Math.round(sourceHeight * scale));
  const offsetX = Math.floor((NORMALIZED_WIDTH - renderedWidth) / 2);
  const offsetY = NORMALIZED_HEIGHT - renderedHeight - 1;
  const pixels = new Float32Array(NORMALIZED_WIDTH * NORMALIZED_HEIGHT);
  for (let targetY = 0; targetY < renderedHeight; targetY += 1) {
    const sourceY = minY + Math.min(sourceHeight - 1, Math.floor((targetY + 0.5) * sourceHeight / renderedHeight));
    for (let targetX = 0; targetX < renderedWidth; targetX += 1) {
      const sourceX = minX + Math.min(sourceWidth - 1, Math.floor((targetX + 0.5) * sourceWidth / renderedWidth));
      pixels[(offsetY + targetY) * NORMALIZED_WIDTH + offsetX + targetX] = cell.mask[sourceY * cell.width + sourceX];
    }
  }
  return { pixels, width: sourceWidth, height: sourceHeight, aspect: sourceWidth / sourceHeight };
}

function buildPrototype(samples) {
  let retained = samples;
  if (samples.length >= 5) {
    const ranked = samples.map((sample, index) => {
      const distances = samples
        .map((other, otherIndex) => otherIndex === index ? null : glyphDistance(sample, other))
        .filter((value) => value !== null)
        .sort((a, b) => a - b);
      const nearest = distances.slice(0, Math.min(4, distances.length));
      return {
        sample,
        score: nearest.reduce((sum, value) => sum + value, 0) / Math.max(1, nearest.length),
      };
    }).sort((a, b) => a.score - b.score);
    retained = ranked.slice(0, Math.max(4, Math.ceil(samples.length * 0.68))).map((item) => item.sample);
  }
  const pixels = new Float32Array(NORMALIZED_WIDTH * NORMALIZED_HEIGHT);
  for (const sample of retained) {
    for (let index = 0; index < pixels.length; index += 1) pixels[index] += sample.pixels[index];
  }
  const divisor = Math.max(1, retained.length);
  for (let index = 0; index < pixels.length; index += 1) pixels[index] /= divisor;
  return {
    pixels,
    samples: retained,
    aspect: retained.reduce((sum, sample) => sum + sample.aspect, 0) / divisor,
    width: retained.reduce((sum, sample) => sum + sample.width, 0) / divisor,
    height: retained.reduce((sum, sample) => sum + sample.height, 0) / divisor,
  };
}

function glyphDistance(glyph, prototype) {
  let difference = 0;
  for (let index = 0; index < glyph.pixels.length; index += 1) {
    difference += Math.abs(glyph.pixels[index] - prototype.pixels[index]);
  }
  const pixelDifference = difference / glyph.pixels.length;
  return pixelDifference + Math.abs(glyph.aspect - prototype.aspect) * 0.12;
}

function classifyGlyph(glyph, prototypes) {
  const scores = Object.entries(prototypes)
    .map(([digit, prototype]) => {
      const sampleScores = (prototype.samples || [])
        .map((sample) => glyphDistance(glyph, sample))
        .sort((a, b) => a - b);
      const nearest = sampleScores.slice(0, Math.min(1, sampleScores.length));
      const distance = nearest.length
        ? nearest.reduce((sum, value) => sum + value, 0) / nearest.length
        : glyphDistance(glyph, prototype);
      return { digit, distance };
    })
    .sort((a, b) => a.distance - b.distance);
  if (!scores.length) return null;
  return {
    digit: scores[0].digit,
    distance: scores[0].distance,
    margin: scores[1] ? scores[1].distance - scores[0].distance : 1,
  };
}

let embeddedPrototypesCache = null;
let embeddedMachinePrototypesCache = null;
let embeddedMaxPayoutPrototypesCache = null;
let ocrWorkerState = null;
let ocrWorkerRequestId = 0;
function prototypesFromSerializedSamples(serialized) {
  const prototypes = {};
  for (const [digit, samples] of Object.entries(serialized)) {
    const hydrated = samples.map((sample) => ({
      width: sample.width,
      height: sample.height,
      aspect: sample.aspect,
      pixels: Float32Array.from(sample.bits, (bit) => bit === "1" ? 1 : 0),
    }));
    prototypes[digit] = buildPrototype(hydrated);
    // 固定テンプレートは事前に検証済みなので、字体の小さな揺れも含めて照合に使う。
    prototypes[digit].samples = hydrated;
  }
  return prototypes;
}

function embeddedDigitPrototypes() {
  if (embeddedPrototypesCache) return embeddedPrototypesCache;
  embeddedPrototypesCache = prototypesFromSerializedSamples(EMBEDDED_DIGIT_SAMPLES);
  return embeddedPrototypesCache;
}

function embeddedMachineDigitPrototypes() {
  if (embeddedMachinePrototypesCache) return embeddedMachinePrototypesCache;
  embeddedMachinePrototypesCache = prototypesFromSerializedSamples(EMBEDDED_MACHINE_DIGIT_SAMPLES);
  return embeddedMachinePrototypesCache;
}

function machineCellForRow(image, verticalLines, row) {
  const left = verticalLines[1];
  const right = verticalLines[2];
  return foregroundMask(image, {
    x0: left.end + 2,
    x1: right.start - 2,
    y0: row.top.end + 2,
    y1: row.bottom.start - 2,
  });
}

function bluePixelRatio(image, verticalLines, row) {
  const left = verticalLines[1].end + 2;
  const right = verticalLines[2].start - 2;
  const top = row.top.end + 2;
  const bottom = row.bottom.start - 2;
  let dark = 0;
  let blue = 0;
  for (let y = top; y < bottom; y += 1) {
    for (let x = left; x < right; x += 1) {
      if (lumaAt(image, x, y) >= DARK_LUMA) continue;
      dark += 1;
      if (isBlueNumberPixel(image, x, y)) blue += 1;
    }
  }
  return dark ? blue / dark : 0;
}

function dataRowCandidates(image, horizontalLines, verticalLines) {
  const rows = [];
  for (let index = 0; index < horizontalLines.length - 1; index += 1) {
    const top = horizontalLines[index];
    const bottom = horizontalLines[index + 1];
    const height = bottom.start - top.end;
    if (height < 7 || height > image.height * 0.08) continue;
    const row = { top, bottom, lineIndex: index };
    const machineCell = machineCellForRow(image, verticalLines, row);
    const groups = columnGroups(machineCell);
    if (groups.length < 1 || groups.length > 5) continue;
    if (bluePixelRatio(image, verticalLines, row) < 0.08) continue;
    rows.push({ ...row, machineCell, machineGroups: groups });
  }
  return rows;
}

function validateExpectedNumbers(expectedNumbers, { allowEmpty = false } = {}) {
  const raw = Array.isArray(expectedNumbers) ? expectedNumbers : [];
  const normalized = raw.map((value) => String(value ?? "").trim());
  if (!normalized.length) {
    if (allowEmpty) return [];
    throw new Error("照合する台番号がありません。先に差玉グラフの台番号を確定してください");
  }
  if (normalized.some((value) => !/^\d+$/u.test(value))) {
    throw new Error("照合する台番号に数字以外が含まれています");
  }
  if (new Set(normalized).size !== normalized.length) {
    throw new Error("照合する台番号が重複しています。差玉側の台番号を確認してください");
  }
  return normalized;
}

export function findSiteSevenMachineNumberOrderConflicts(machineNumbers, expectedNumbers) {
  const expectedOrder = new Map((Array.isArray(expectedNumbers) ? expectedNumbers : [])
    .map((value, index) => [String(value ?? "").trim(), index]));
  const conflicts = new Set();
  let previous = null;
  (Array.isArray(machineNumbers) ? machineNumbers : []).forEach((value, index) => {
    const order = expectedOrder.get(String(value ?? "").trim());
    if (!Number.isInteger(order)) return;
    if (previous && order <= previous.order) {
      conflicts.add(previous.index);
      conflicts.add(index);
    }
    previous = { index, order };
  });
  return [...conflicts].sort((left, right) => left - right);
}

function splitGroupAtValley(cell, group) {
  const middle = (group.x0 + group.x1) / 2;
  let bestCut = -1;
  let bestScore = Number.POSITIVE_INFINITY;
  for (let cut = group.x0 + 2; cut <= group.x1 - 2; cut += 1) {
    let left = 0;
    let right = 0;
    for (let y = group.y0; y < group.y1; y += 1) {
      left += cell.mask[y * cell.width + cut - 1];
      right += cell.mask[y * cell.width + cut];
    }
    const score = left + right + Math.abs(cut - middle) * 0.18;
    if (score < bestScore) {
      bestScore = score;
      bestCut = cut;
    }
  }
  if (bestCut < 0) return null;
  return [
    { ...group, x1: bestCut },
    { ...group, x0: bestCut },
  ];
}

function groupsForExactCount(cell, expectedCount) {
  const groups = columnGroups(cell);
  while (groups.length < expectedCount) {
    let widestIndex = -1;
    let widest = 0;
    groups.forEach((group, index) => {
      const width = group.x1 - group.x0;
      if (width > widest) {
        widest = width;
        widestIndex = index;
      }
    });
    if (widestIndex < 0 || widest < 5) return null;
    const split = splitGroupAtValley(cell, groups[widestIndex]);
    if (!split) return null;
    groups.splice(widestIndex, 1, ...split);
  }
  while (groups.length > expectedCount) {
    let nearestIndex = -1;
    let nearestGap = Number.POSITIVE_INFINITY;
    for (let index = 0; index < groups.length - 1; index += 1) {
      const gap = groups[index + 1].x0 - groups[index].x1;
      if (gap < nearestGap) {
        nearestGap = gap;
        nearestIndex = index;
      }
    }
    if (nearestIndex < 0 || nearestGap > 2) return null;
    groups.splice(nearestIndex, 2, {
      x0: groups[nearestIndex].x0,
      x1: groups[nearestIndex + 1].x1,
      y0: Math.min(groups[nearestIndex].y0, groups[nearestIndex + 1].y0),
      y1: Math.max(groups[nearestIndex].y1, groups[nearestIndex + 1].y1),
    });
  }
  return groups;
}

function recognizeMachineMapping(image, rows, expectedNumbers, verticalLines, {
  allowRawMachineNumbers = false,
} = {}) {
  const expected = validateExpectedNumbers(expectedNumbers, { allowEmpty: allowRawMachineNumbers });
  const expectedSet = new Set(expected);
  const hasExpectedNumbers = expectedSet.size > 0;
  const prototypes = embeddedMachineDigitPrototypes();
  const mapped = rows.map((row) => {
    const recognition = recognizeCellEnsemble(
      image,
      rowCellBounds(verticalLines, row, 1),
      prototypes
    );
    const candidate = recognition.value || "";
    const unanimous = recognition.variants.length === 3
      && recognition.variants.every((value) => value === candidate);
    const accepted = Boolean(candidate)
      && (!hasExpectedNumbers || expectedSet.has(candidate))
      && unanimous
      && recognition.baseReasons.length === 0
      && recognition.confidence >= 0.25;
    return {
      ...row,
      num: candidate,
      machineNumberCandidate: candidate,
      machineNumberRecognition: recognition,
      machineNumberAccepted: accepted,
      machineNumberReviewReason: !candidate
        ? "台番号を読み取れませんでした"
        : hasExpectedNumbers && !expectedSet.has(candidate)
          ? `差玉側に台${candidate}がありません`
          : !unanimous
            ? "台番号の読み取り結果が条件によって一致しません"
            : recognition.baseReasons.length > 0 || recognition.confidence < 0.25
              ? "台番号を十分な精度で読めませんでした"
              : "",
    };
  });

  const byNumber = new Map();
  for (const row of mapped) {
    if (!row.num) continue;
    if (!byNumber.has(row.num)) byNumber.set(row.num, []);
    byNumber.get(row.num).push(row);
  }
  for (const duplicates of byNumber.values()) {
    if (duplicates.length < 2) continue;
    for (const row of duplicates) {
      row.machineNumberAccepted = false;
      row.machineNumberReviewReason = `台番号${row.num}を画像内で重複検出しました`;
    }
  }

  const orderConflictIndexes = hasExpectedNumbers
    ? findSiteSevenMachineNumberOrderConflicts(
      mapped.map((row) => row.machineNumberAccepted ? row.num : ""),
      expected
    )
    : [];
  for (const index of orderConflictIndexes) {
    mapped[index].machineNumberAccepted = false;
    mapped[index].machineNumberReviewReason = "台番号の並び順が前後の行と一致しません";
  }
  const consecutiveLines = rows.every((row, index) => (
    index === 0 || row.lineIndex === rows[index - 1].lineIndex + 1
  ));
  const degradedReasons = [
    ...(!consecutiveLines ? ["table-row-gap"] : []),
    ...(orderConflictIndexes.length > 0 ? ["machine-number-order"] : []),
  ];
  const acceptedCount = mapped.filter((row) => row.machineNumberAccepted).length;
  return {
    mapped,
    accuracy: mapped.length ? acceptedCount / mapped.length : 0,
    acceptedCount,
    machineNumberMode: hasExpectedNumbers ? "expected" : "raw",
    consecutiveLines,
    degradedReasons,
  };
}

function recognizeMaskedCell(cell, prototypes, { widthPenaltyWeight = 0.42 } = {}) {
  const contentBounds = maskBounds(cell.mask, cell.width, cell.height);
  if (!contentBounds) return { value: "", confidence: 0, reasons: ["empty-cell"] };
  const contentWidth = contentBounds.maxX - contentBounds.minX + 1;
  const candidates = [];
  for (let digitCount = 1; digitCount <= 6; digitCount += 1) {
    const groups = groupsForExactCount(cell, digitCount);
    if (!groups) continue;
    const recognized = groups.map((rect) => {
      const glyph = normalizeGlyph(cell, rect);
      return glyph ? classifyGlyph(glyph, prototypes) : null;
    });
    if (recognized.some((result) => !result)) continue;
    const value = recognized.map((result) => result.digit).join("");
    const meanDistance = recognized.reduce((sum, result) => sum + result.distance, 0) / recognized.length;
    const leadingZeroPenalty = value.length > 1 && value.startsWith("0") ? 0.12 : 0;
    const expectedWidth = recognized.reduce((sum, result) => sum + (prototypes[result.digit]?.width || 0), 0)
      + Math.max(0, digitCount - 1);
    const widthPenalty = Math.abs(expectedWidth - contentWidth) / Math.max(1, contentWidth)
      * widthPenaltyWeight;
    candidates.push({
      value,
      recognized,
      distance: meanDistance,
      score: meanDistance + leadingZeroPenalty + widthPenalty + digitCount * 0.001,
    });
  }
  candidates.sort((a, b) => a.score - b.score);
  const best = candidates[0];
  if (!best) return { value: "", confidence: 0, reasons: ["unrecognized-glyph"] };
  const sequenceMargin = candidates[1] ? candidates[1].score - best.score : 1;
  const reasons = [];
  if (best.distance > 0.25
    || sequenceMargin < 0.012
    || best.recognized.some((result) => result.margin < 0.008)) {
    reasons.push("low-confidence-glyph");
  }
  const confidence = best.recognized.reduce((lowest, result) => Math.min(
    lowest,
    clamp((0.34 - result.distance) / 0.2, 0, 1),
    clamp(result.margin / 0.05, 0, 1)
  ), clamp(sequenceMargin / 0.05, 0, 1));
  return {
    value: best.value,
    confidence,
    reasons: [...new Set(reasons)],
    glyphs: best.recognized,
    candidates: candidates.slice(0, 8).map((candidate) => ({
      value: candidate.value,
      distance: candidate.distance,
      score: candidate.score,
    })),
  };
}

function recognizeCell(image, bounds, prototypes, darkLuma = DARK_LUMA, options = {}) {
  return recognizeMaskedCell(foregroundMask(image, bounds, darkLuma), prototypes, options);
}

function summarizeRecognitionEnsemble(variants) {
  const counts = new Map();
  for (const variant of variants) {
    if (!variant.value) continue;
    counts.set(variant.value, (counts.get(variant.value) || 0) + 1);
  }
  const selected = variants[Math.floor(variants.length / 2)];
  const unanimous = Boolean(selected.value)
    && variants.every((variant) => variant.value === selected.value);
  return {
    ...selected,
    reasons: [...new Set([
      ...(selected.reasons || []),
      ...(!unanimous ? ["threshold-disagreement"] : []),
    ])],
    baseReasons: selected.reasons || [],
    ensembleDisagreed: !unanimous,
    unanimous,
    variants: variants.map((variant) => variant.value),
  };
}

function recognizeCellEnsemble(image, bounds, prototypes, options = {}) {
  const variants = [184, DARK_LUMA, 186]
    .map((threshold) => recognizeCell(image, bounds, prototypes, threshold, options));
  return summarizeRecognitionEnsemble(variants);
}

function rowCellBounds(verticalLines, row, columnIndex) {
  return {
    x0: verticalLines[columnIndex].end + 2,
    x1: verticalLines[columnIndex + 1].start - 2,
    y0: row.top.end + 2,
    y1: row.bottom.start - 2,
  };
}

function resizeImageData(image, scale) {
  const width = Math.max(1, Math.round(image.width * scale));
  const height = Math.max(1, Math.round(image.height * scale));
  const data = new Uint8ClampedArray(width * height * 4);
  for (let y = 0; y < height; y += 1) {
    const sourceY = clamp((y + 0.5) / scale - 0.5, 0, image.height - 1);
    const y0 = Math.floor(sourceY);
    const y1 = Math.min(image.height - 1, y0 + 1);
    const fy = sourceY - y0;
    for (let x = 0; x < width; x += 1) {
      const sourceX = clamp((x + 0.5) / scale - 0.5, 0, image.width - 1);
      const x0 = Math.floor(sourceX);
      const x1 = Math.min(image.width - 1, x0 + 1);
      const fx = sourceX - x0;
      const target = (y * width + x) * 4;
      const topLeft = pixelOffset(image, x0, y0);
      const topRight = pixelOffset(image, x1, y0);
      const bottomLeft = pixelOffset(image, x0, y1);
      const bottomRight = pixelOffset(image, x1, y1);
      for (let channel = 0; channel < 4; channel += 1) {
        const top = image.data[topLeft + channel] * (1 - fx) + image.data[topRight + channel] * fx;
        const bottom = image.data[bottomLeft + channel] * (1 - fx) + image.data[bottomRight + channel] * fx;
        data[target + channel] = Math.round(top * (1 - fy) + bottom * fy);
      }
    }
  }
  return { width, height, data };
}

function normalizeTableScale(image) {
  const result = {
    image,
    reasons: [],
    resampled: false,
    tableWidth: null,
  };
  try {
    const horizontalLines = detectHorizontalLines(image);
    const geometry = detectVerticalLines(image, horizontalLines);
    const tableWidth = geometry.tableRight - geometry.tableLeft;
    const targetTableWidth = 338;
    result.tableWidth = tableWidth;
    if (Math.abs(tableWidth - targetTableWidth) <= 3) return result;
    const scale = targetTableWidth / Math.max(1, tableWidth);
    // 小さい写真の再拡大は、見た目だけを補間して誤読を増やすため行わない。
    if (scale > 1) {
      result.reasons.push("low-resolution-table");
      return result;
    }
    result.image = resizeImageData(image, scale);
    result.resampled = true;
    return result;
  } catch {
    return result;
  }
}

// 開発時にサイトセブンの実画像から数字字体を採取するための補助関数。
// 実行時のOCRでは呼ばない。
export function createSiteSevenDigitTemplateFixture(image, {
  groundTruthRows = [],
  samplesPerDigit = 8,
} = {}) {
  const inspected = inspectSiteSevenTableStructure(image);
  if (!Array.isArray(groundTruthRows) || groundTruthRows.length !== inspected.rows.length) {
    throw new Error("全行分の正解データをgroundTruthRowsへ明示してください");
  }
  const samplesByDigit = {};
  for (let rowIndex = 0; rowIndex < inspected.rows.length; rowIndex += 1) {
    const mappedRow = inspected.rows[rowIndex];
    const truth = groundTruthRows[rowIndex];
    if (!truth) throw new Error(`${rowIndex + 1}行目の正解データがありません`);
    const labeledCells = [
      [3, truth.normalSpins],
      [5, truth.maxPayout],
      [6, truth.totalStarts],
    ].filter(([, rawValue]) => rawValue !== null && rawValue !== undefined && rawValue !== "");
    if (!labeledCells.length) {
      throw new Error(`${rowIndex + 1}行目に数字字体の正解データがありません`);
    }
    for (const [columnIndex, rawValue] of labeledCells) {
      const value = String(rawValue);
      const cell = foregroundMask(image, rowCellBounds(inspected.geometry.lines, mappedRow, columnIndex));
      const groups = groupsForExactCount(cell, value.length);
      if (!groups) continue;
      groups.forEach((rect, index) => {
        const glyph = normalizeGlyph(cell, rect);
        if (!glyph) return;
        const digit = value[index];
        if (!samplesByDigit[digit]) samplesByDigit[digit] = [];
        samplesByDigit[digit].push(glyph);
      });
    }
  }
  const fixture = {};
  for (const [digit, samples] of Object.entries(samplesByDigit)) {
    const uniqueByShape = new Map();
    for (const sample of samples) {
      const bits = Array.from(sample.pixels, (value) => value >= 0.5 ? "1" : "0").join("");
      const key = `${sample.width}:${sample.height}:${bits}`;
      if (!uniqueByShape.has(key)) uniqueByShape.set(key, { ...sample, bits });
    }
    const uniqueSamples = Array.from(uniqueByShape.values());
    const ranked = uniqueSamples.map((sample, index) => {
      const distances = uniqueSamples
        .map((other, otherIndex) => otherIndex === index ? null : glyphDistance(sample, other))
        .filter((value) => value !== null)
        .sort((a, b) => a - b)
        .slice(0, Math.min(5, uniqueSamples.length - 1));
      return {
        sample,
        score: distances.reduce((sum, value) => sum + value, 0) / Math.max(1, distances.length),
      };
    }).sort((a, b) => a.score - b.score);
    fixture[digit] = ranked.slice(0, samplesPerDigit).map(({ sample }) => ({
      width: sample.width,
      height: sample.height,
      aspect: Number(sample.aspect.toFixed(5)),
      bits: sample.bits,
    }));
  }
  return fixture;
}

export function createSiteSevenMachineDigitTemplateFixture(image, {
  groundTruthNumbers = [],
  samplesPerDigit = 999,
} = {}) {
  const inspected = inspectSiteSevenTableStructure(image);
  const labels = Array.isArray(groundTruthNumbers)
    ? groundTruthNumbers.map((value) => String(value ?? "").trim())
    : [];
  if (labels.length !== inspected.rows.length || labels.some((value) => !/^\d+$/u.test(value))) {
    throw new Error("全行分の正しい台番号をgroundTruthNumbersへ明示してください");
  }
  const samplesByDigit = {};
  inspected.rows.forEach((mappedRow, rowIndex) => {
    const label = labels[rowIndex];
    const groups = groupsForExactCount(mappedRow.machineCell, label.length);
    if (!groups) throw new Error(`${rowIndex + 1}行目の台番号字体を分割できませんでした`);
    groups.forEach((rect, index) => {
      const glyph = normalizeGlyph(mappedRow.machineCell, rect);
      if (!glyph) throw new Error(`${rowIndex + 1}行目の台番号字体を抽出できませんでした`);
      const digit = label[index];
      if (!samplesByDigit[digit]) samplesByDigit[digit] = [];
      samplesByDigit[digit].push(glyph);
    });
  });
  const fixture = {};
  for (const [digit, samples] of Object.entries(samplesByDigit)) {
    const uniqueByShape = new Map();
    for (const sample of samples) {
      const bits = Array.from(sample.pixels, (value) => value >= 0.5 ? "1" : "0").join("");
      const key = `${sample.width}:${sample.height}:${bits}`;
      if (!uniqueByShape.has(key)) uniqueByShape.set(key, { ...sample, bits });
    }
    const uniqueSamples = Array.from(uniqueByShape.values());
    fixture[digit] = uniqueSamples.slice(0, samplesPerDigit).map((sample) => ({
      width: sample.width,
      height: sample.height,
      aspect: Number(sample.aspect.toFixed(5)),
      bits: sample.bits,
    }));
  }
  return fixture;
}

export function debugRecognizeSiteSevenCell(image, {
  expectedNumbers = [],
  allowRawMachineNumbers = false,
  rowIndex = 0,
  columnIndex = 3,
  digitSamples = null,
} = {}) {
  const inspected = inspectSiteSevenTableImage(image, { expectedNumbers, allowRawMachineNumbers });
  const row = inspected.mapping.mapped[rowIndex];
  if (!row) throw new Error("指定された確認行がありません");
  const prototypes = columnIndex === 1
    ? embeddedMachineDigitPrototypes()
    : columnIndex === 5
      ? digitSamples
        ? prototypesFromSerializedSamples(digitSamples)
        : embeddedMaxPayoutDigitPrototypes()
      : prototypesFromSerializedSamples(digitSamples || EMBEDDED_DIGIT_SAMPLES);
  return recognizeCellEnsemble(
    image,
    rowCellBounds(inspected.geometry.lines, row, columnIndex),
    prototypes,
    columnIndex === 5 ? { widthPenaltyWeight: 0 } : {},
  );
}

export function inspectSiteSevenTableStructure(image) {
  if (!image?.data || !Number.isInteger(image.width) || !Number.isInteger(image.height)) {
    throw new Error("写真の画像データを読み込めませんでした");
  }
  if (image.width * image.height > 20_000_000) {
    throw new Error("写真が大きすぎます。表全体が読める範囲で切り抜いてから選び直してください");
  }
  const horizontalLines = detectHorizontalLines(image);
  if (horizontalLines.length < 3) throw new Error("写真からサイトセブン表の罫線を確認できませんでした");
  const geometry = detectVerticalLines(image, horizontalLines);
  const rows = dataRowCandidates(image, horizontalLines, geometry.lines);
  if (!rows.length) throw new Error("写真から台番号の行を確認できませんでした");
  return { image, horizontalLines, geometry, rows };
}

export function inspectSiteSevenTableImage(image, {
  expectedNumbers = [],
  allowRawMachineNumbers = false,
} = {}) {
  const structure = inspectSiteSevenTableStructure(image);
  const { rows } = structure;
  const mapping = recognizeMachineMapping(
    image,
    rows,
    expectedNumbers,
    structure.geometry.lines,
    { allowRawMachineNumbers },
  );
  return { ...structure, mapping };
}

function embeddedMaxPayoutDigitPrototypes() {
  if (embeddedMaxPayoutPrototypesCache) return embeddedMaxPayoutPrototypesCache;
  embeddedMaxPayoutPrototypesCache = prototypesFromSerializedSamples(
    SITE_SEVEN_MAX_PAYOUT_DIGIT_SAMPLES,
  );
  return embeddedMaxPayoutPrototypesCache;
}

export function parseSiteSevenTableImageData(image, {
  expectedNumbers = [],
  allowRawMachineNumbers = false,
  dateText = "",
  storeName = "",
  fileName = "",
  digitSamples = null,
  maxPayoutDigitSamples = null,
} = {}) {
  const scaleInfo = normalizeTableScale(image);
  const normalizedImage = scaleInfo.image;
  const inspected = inspectSiteSevenTableImage(normalizedImage, {
    expectedNumbers,
    allowRawMachineNumbers,
  });
  const { geometry, mapping } = inspected;
  const digitPrototypes = digitSamples
    ? prototypesFromSerializedSamples(digitSamples)
    : embeddedDigitPrototypes();
  const maxPayoutDigitPrototypes = maxPayoutDigitSamples
    ? prototypesFromSerializedSamples(maxPayoutDigitSamples)
    : embeddedMaxPayoutDigitPrototypes();
  const recognizedRows = [];
  for (let index = 0; index < mapping.mapped.length; index += 1) {
    const mappedRow = mapping.mapped[index];
    const normal = recognizeCellEnsemble(normalizedImage, rowCellBounds(geometry.lines, mappedRow, 3), digitPrototypes);
    const maxPayout = recognizeCellEnsemble(
      normalizedImage,
      rowCellBounds(geometry.lines, mappedRow, 5),
      maxPayoutDigitPrototypes,
      { widthPenaltyWeight: 0 },
    );
    const jackpot = recognizeCellEnsemble(normalizedImage, rowCellBounds(geometry.lines, mappedRow, 6), digitPrototypes);
    recognizedRows.push({
      normal,
      maxPayout,
      jackpot,
      mappedRow,
      index,
    });
  }
  const degradedReasons = [...scaleInfo.reasons, ...mapping.degradedReasons];
  const uniqueDegradedReasons = [...new Set(degradedReasons)];
  const degradedImage = uniqueDegradedReasons.length > 0;
  const globalReviewMessages = uniqueDegradedReasons.map((reason) => {
    if (reason === "low-resolution-table") {
      return "写真の表が小さいため、元画像または高解像度の写真で数字を確認してください";
    }
    if (reason === "table-row-gap") {
      return "表の途中に読み取れない行があるため、台番号と行の対応を確認してください";
    }
    if (reason === "machine-number-order") {
      return "台番号の並び順に矛盾があるため、この写真の全台を目視確認してください";
    }
    return "画像の圧縮または字体差を検出したため、数字を目視確認してください";
  });
  const recognitionReviewReason = (label, recognition) => {
    if (!recognition.value) return `${label}を読み取れませんでした`;
    if (!recognition.unanimous) return `${label}の読み取り結果が条件によって一致しません`;
    const hasDistantGlyph = recognition.glyphs?.some((glyph) => glyph.distance > 0.04);
    if (recognition.baseReasons.length > 0 || recognition.confidence < 0.3 || hasDistantGlyph) {
      return `${label}を十分な精度で読めませんでした`;
    }
    return "";
  };
  const maxPayoutReviewReasonFor = (recognition) => {
    // The maximum-payout column uses its own fixed glyph bank. A glyph that is an
    // almost exact match is stronger evidence than the generic segmentation
    // margin (which can be small when a trailing zero is faintly connected).
    const exactTemplateMatch = /^\d+$/.test(recognition.value || "")
      && recognition.glyphs?.length > 0
      && recognition.glyphs.every((glyph) => glyph.distance <= 0.002)
      && (recognition.candidates?.[0]?.distance ?? 1) <= 0.002;
    return exactTemplateMatch
      ? ""
      : recognitionReviewReason("最高出玉", recognition);
  };
  const rows = [];
  const skipped = [];
  for (const { normal, maxPayout, jackpot, mappedRow, index } of recognizedRows) {
    const normalReviewReason = recognitionReviewReason("通常中スタート", normal);
    const maxPayoutReviewReason = maxPayoutReviewReasonFor(maxPayout);
    const jackpotReviewReason = recognitionReviewReason("大当たり回数", jackpot);
    const nonNumberReviewMessages = [
      ...globalReviewMessages,
      ...(normalReviewReason ? [normalReviewReason] : []),
      ...(jackpotReviewReason ? [jackpotReviewReason] : []),
    ].filter(Boolean);
    const rowReviewMessages = [
      ...nonNumberReviewMessages,
      ...(!mappedRow.machineNumberAccepted ? [mappedRow.machineNumberReviewReason] : []),
    ].filter(Boolean);
    const needsReview = rowReviewMessages.length > 0;
    const row = {
      date: String(dateText || ""),
      store: String(storeName || ""),
      island: "",
      machineName: "",
      num: mappedRow.num,
      normalSpins: normal.value,
      maxPayout: maxPayout.value,
      totalStarts: jackpot.value,
      sourceFile: String(fileName || ""),
      sourceLine: index + 1,
      sourceType: "local-image-ocr",
      reviewRequired: needsReview,
      reviewConfirmed: false,
      globalReviewRequired: globalReviewMessages.length > 0,
      nonNumberReviewRequired: nonNumberReviewMessages.length > 0,
      nonNumberReviewReason: [...new Set(nonNumberReviewMessages)].join("。"),
      ocrConfidence: Math.min(
        mappedRow.machineNumberRecognition.confidence,
        normal.confidence,
        jackpot.confidence
      ),
      reviewReason: [...new Set(rowReviewMessages)].join("。"),
      // 既存の reviewRequired / ocrConfidence は、これまでと同じ3項目の集約を維持する。
      // 最高出玉はグラフとの照合用フィールドなので、低信頼時も他の正しい行を巻き込まず
      // field-level の状態だけで安全に止める。
      numAccepted: mappedRow.machineNumberAccepted,
      normalSpinsAccepted: !normalReviewReason,
      maxPayoutAccepted: !maxPayoutReviewReason,
      totalStartsAccepted: !jackpotReviewReason,
      numConfidence: mappedRow.machineNumberRecognition.confidence,
      normalSpinsConfidence: normal.confidence,
      maxPayoutConfidence: maxPayout.confidence,
      totalStartsConfidence: jackpot.confidence,
      numCandidates: mappedRow.machineNumberRecognition.candidates || [],
      maxPayoutCandidates: maxPayout.candidates || [],
      fieldConfidence: {
        num: mappedRow.machineNumberRecognition.confidence,
        normalSpins: normal.confidence,
        maxPayout: maxPayout.confidence,
        totalStarts: jackpot.confidence,
      },
      fieldAccepted: {
        num: mappedRow.machineNumberAccepted,
        normalSpins: !normalReviewReason,
        maxPayout: !maxPayoutReviewReason,
        totalStarts: !jackpotReviewReason,
      },
      fieldReviewRequired: {
        num: !mappedRow.machineNumberAccepted,
        normalSpins: Boolean(normalReviewReason),
        maxPayout: Boolean(maxPayoutReviewReason),
        totalStarts: Boolean(jackpotReviewReason),
      },
      fieldReviewReason: {
        num: mappedRow.machineNumberReviewReason || "",
        normalSpins: normalReviewReason,
        maxPayout: maxPayoutReviewReason,
        totalStarts: jackpotReviewReason,
      },
    };
    rows.push(row);
    if (needsReview) {
      skipped.push({
        lineNumber: index + 1,
        num: mappedRow.num,
        reason: row.reviewReason,
        machineNumberReasons: mappedRow.machineNumberRecognition.reasons,
        normalReasons: normal.reasons,
        jackpotReasons: jackpot.reasons,
      });
    }
  }
  return {
    rows,
    skipped,
    duplicates: [],
    sourceType: "local-image-ocr",
    machineNumberAccuracy: mapping.accuracy,
    machineNumberMode: mapping.machineNumberMode,
    degradedImage,
    degradedReasons: uniqueDegradedReasons,
  };
}

function getOcrWorkerState() {
  if (ocrWorkerState) return ocrWorkerState;
  if (typeof Worker === "undefined") return null;
  try {
    const worker = new Worker(new URL("./siteSevenImageOcrWorker.js", import.meta.url), { type: "module" });
    const pending = new Map();
    worker.onmessage = (event) => {
      const response = event.data || {};
      const request = pending.get(response.id);
      if (!request) return;
      pending.delete(response.id);
      if (response.ok) request.resolve(response.result);
      else request.reject(new Error(response.message || "写真の読み取りに失敗しました"));
    };
    worker.onerror = () => {
      for (const request of pending.values()) request.reject(new Error("写真解析処理を開始できませんでした"));
      pending.clear();
      worker.terminate();
      ocrWorkerState = null;
    };
    ocrWorkerState = { worker, pending };
    return ocrWorkerState;
  } catch {
    return null;
  }
}

function parseSiteSevenTableImageOffMainThread(imageData, options) {
  const state = getOcrWorkerState();
  if (!state) return null;
  const id = ++ocrWorkerRequestId;
  const buffer = imageData.data.buffer;
  return new Promise((resolve, reject) => {
    state.pending.set(id, { resolve, reject });
    try {
      state.worker.postMessage({
        id,
        image: { width: imageData.width, height: imageData.height, buffer },
        options,
      }, [buffer]);
    } catch (error) {
      state.pending.delete(id);
      reject(error);
    }
  });
}

function loadImageElement(file) {
  return new Promise((resolve, reject) => {
    const url = URL.createObjectURL(file);
    const image = new Image();
    image.onload = () => {
      URL.revokeObjectURL(url);
      resolve(image);
    };
    image.onerror = () => {
      URL.revokeObjectURL(url);
      reject(new Error("写真を開けませんでした"));
    };
    image.src = url;
  });
}

export async function readSiteSevenImage(file, options = {}) {
  if (!file) throw new Error("写真ファイルを選んでください");
  const image = await loadImageElement(file);
  const width = image.naturalWidth || image.width;
  const height = image.naturalHeight || image.height;
  if (width * height > 20_000_000) {
    throw new Error("写真が大きすぎます。表全体が読める範囲で切り抜いてから選び直してください");
  }
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const context = canvas.getContext("2d", { willReadFrequently: true });
  context.drawImage(image, 0, 0);
  const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
  const parseOptions = { ...options, fileName: file.name || "" };
  const workerResult = parseSiteSevenTableImageOffMainThread(imageData, parseOptions);
  return workerResult || parseSiteSevenTableImageData(imageData, parseOptions);
}
